// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract LandRegistry {
    struct Seller {
        string aadhaar;
        string name;
        string mobile;
        string addr;
        string email;
    }

    struct Land {
        string area;
        string city;
        uint256 amount;
        uint256 advance;
        string imageHash;
        string squareFeet;
        string documentNo;
        string surveyNo;
        address owner;
    }

    mapping(address => Seller) public sellers;
    mapping(string => Land) public lands;
    string[] public landIds;

    event SellerRegistered(address indexed sellerAddress, string aadhaar);
    event LandRegistered(string indexed documentNo, string indexed surveyNo, address indexed owner);

    // First, the seller registers their details separately
    function registerSeller(
        string memory _aadhaar,
        string memory _name,
        string memory _mobile,
        string memory _addr,
        string memory _email
    ) public {
        sellers[msg.sender] = Seller(_aadhaar, _name, _mobile, _addr, _email);
        emit SellerRegistered(msg.sender, _aadhaar);
    }

    // Then, the seller registers the land details
    function addLand(
        string memory _area,
        string memory _city,
        uint256 _amount,
        uint256 _advance,
        string memory _imageHash,
        string memory _squareFeet,
        string memory _documentNo,
        string memory _surveyNo
    ) public {
        require(bytes(sellers[msg.sender].aadhaar).length != 0, "Seller not registered!");

        lands[_documentNo] = Land({
            area: _area,
            city: _city,
            amount: _amount,
            advance: _advance,
            imageHash: _imageHash,
            squareFeet: _squareFeet,
            documentNo: _documentNo,
            surveyNo: _surveyNo,
            owner: msg.sender
        });

        landIds.push(_documentNo);
        emit LandRegistered(_documentNo, _surveyNo, msg.sender);
    }

    function getLand(string memory _documentNo) public view returns (Land memory) {
        return lands[_documentNo];
    }

    function getAllLands() public view returns (string[] memory) {
        return landIds;
    }
}

